import asyncio
import json
import sys
from types import SimpleNamespace


async def load_user(user_id):
    return f"{user_id}:user"


async def load_profile(user_id):
    return f"{user_id}:profile"


def merge(user, profile):
    return f"{user}|{profile}"


async def app(input):
    user, profile = await asyncio.gather(
        load_user(input.user_id),
        load_profile(input.user_id),
    )
    summary = merge(user, profile)
    return summary


if __name__ == "__main__":
    input_json = sys.argv[1] if len(sys.argv) > 1 else '{"userId":"ada"}'
    payload = json.loads(input_json)
    input = SimpleNamespace(user_id=payload["userId"])
    print(asyncio.run(app(input)))
